/**
 * Generated by `createservice miniapp.SendDTMFToB2CAppService --type mutations`
 */
const conf = require('@open-condo/config')
const { GQLError, GQLErrorCode: { BAD_USER_INPUT, FORBIDDEN, INTERNAL_ERROR, NOT_FOUND } } = require('@open-condo/keystone/errors')
const { getLogger } = require('@open-condo/keystone/logging')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema, getByCondition } = require('@open-condo/keystone/schema')

const { WRONG_FORMAT, DV_VERSION_MISMATCH } = require('@condo/domains/common/constants/errors')
const access = require('@condo/domains/miniapp/access/SendDTMFToB2CAppService')
const {
    APP_NOT_FOUND_ERROR,
} = require('@condo/domains/miniapp/constants')

const logger = getLogger()

/** 
 * @typedef {Object} IntercomServerConfig 
 * @property {string} url 
 * @property {string} accessToken
 */

/** @typedef {String} B2CAppId */

/** 
 * @typedef {Record<B2CAppId, IntercomServerConfig>} SendDTMFToB2CAppServiceConfig 
 */

/** @type {SendDTMFToB2CAppServiceConfig} */
const SEND_DTMF_TO_B2C_APP_SERVICE_CONFIG = JSON.parse(conf.SEND_DTMF_TO_B2C_APP_SERVICE_CONFIG || '{}') || {}

const SERVICE_NAME = 'sendDTMFToB2CApp'
const ERRORS = {
    APP_NOT_FOUND: {
        mutation: SERVICE_NAME,
        code: BAD_USER_INPUT,
        type: APP_NOT_FOUND_ERROR,
        message: 'Unable to find app by provided id.',
        messageForUser: `api.miniapp.${SERVICE_NAME}.APP_NOT_FOUND`,
    },
    DV_VERSION_MISMATCH: {
        mutation: SERVICE_NAME,
        variable: ['data', 'dv'],
        code: BAD_USER_INPUT,
        type: DV_VERSION_MISMATCH,
        message: 'Wrong value for data version number',
        messageForUser: `api.miniapp.${SERVICE_NAME}.DV_VERSION_MISMATCH`,
    },
    WRONG_SENDER_FORMAT: {
        mutation: SERVICE_NAME,
        variable: ['data', 'sender'],
        code: BAD_USER_INPUT,
        type: WRONG_FORMAT,
        message: 'Invalid format of "sender" field value. {details}',
        correctExample: '{ "dv": 1, "fingerprint": "uniq-device-or-container-id" }',
        messageInterpolation: { details: 'Please, check the example for details' },
        messageForUser: `api.miniapp.${SERVICE_NAME}.WRONG_SENDER_FORMAT`,
    },
    CALL_NOT_FOUND: {
        mutation: SERVICE_NAME,
        code: NOT_FOUND,
        type: 'CALL_NOT_FOUND',
        message: 'Call for that callId is already ended or never existed',
        messageForUser: '',
        variable: ['data', 'callId'],
    },
    INVALID_CONFIG: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'INVALID_CONFIG',
        message: 'Config is not configured properly',
    },
    INVALID_DTMF_CODE: {
        mutation: SERVICE_NAME,
        code: BAD_USER_INPUT,
        type: 'INVALID_DTMF_CODE',
        message: 'DTMF code is empty',
        variable: ['data', 'data', 'dtmfCode'],
    },
    INVALID_ACCESS_TOKEN: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'INVALID_ACCESS_TOKEN',
        message: 'Access token for intercoms is invalid',
    },
    UNKNOWN_ERROR: {
        mutation: SERVICE_NAME,
        code: INTERNAL_ERROR,
        type: 'UNKNOWN_ERROR',
        message: 'Unknown error',
    },
    APP_NOT_ALLOWED: {
        mutation: SERVICE_NAME,
        code: FORBIDDEN,
        type: 'APP_NOT_ALLOWED',
        message: 'You are not allowed to send dtmf for this app',
    },
}

// there will be an util function after DOMA-12905
async function getCallStatus ({ b2cAppId, callId }) {
    return { status: 'active' }
}

async function sendDTMFCode ({ url, dtmfCode, accessToken }) {
    if (!dtmfCode) {
        return ERRORS.INVALID_DTMF_CODE
    }

    if (!accessToken || !url) {
        return ERRORS.INVALID_CONFIG
    }

    let error = null
    let response = null
    let responseJSON = null

    try {
        response = await fetch(url, {
            method: 'POST',
            headers: {
                Authorization: `Bearer ${accessToken}`,
            },
        })

        responseJSON = await response.json()
    } catch (err) {
        logger.error({ msg: 'sendDTMFCode result', err })
        return ERRORS.UNKNOWN_ERROR
    }

    if (!response) return error

    if (response.status < 200 || response.status > 299) {
        error = ERRORS.UNKNOWN_ERROR
        
        if (response.status === 403) {
            error = ERRORS.INVALID_ACCESS_TOKEN
        }
        
        if (response.status === 404) {
            error = ERRORS.CALL_NOT_FOUND
        }
    }

    logger.info({ msg: 'sendDTMFCode result', data: { responseJSON, status: response?.status } })
    return error
}

const SendDTMFToB2CAppService = new GQLCustomSchema('SendDTMFToB2CAppService', {
    types: [
        {
            access: true,
            type: `input SendDTMFToB2CAppData {
            """
            Code for opening intercom, same which was sent in voip call
            """
            dtmfCode: String!
            }`,
        },
        {
            access: true,
            type: `input SendDTMFToB2CAppInput {
                    dv: Int!,
                    sender: SenderFieldInput!,
                    app: B2CAppWhereUniqueInput!,
                    """
                    Same "callId" which been sent in sendVoIPStartMessage
                    """
                    callId: String!,
                    data: SendDTMFToB2CAppData!
                }`,
        },
        {
            access: true,
            type: `type SendDTMFToB2CAppOutput { 
                  """
                  "OK" string, otherwise an error will be thrown
                  """
                  status: String! 
                }`,
        },
    ],
    
    mutations: [
        {
            access: access.canSendDTMFToB2CApp,
            schema: 'sendDTMFToB2CApp(data: SendDTMFToB2CAppInput!): SendDTMFToB2CAppOutput',
            resolver: async (parent, args, context) => {
                const { data: argsData } = args
                const { app, callId, data: { dtmfCode } } = argsData

                checkDvAndSender(argsData, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                if (!SEND_DTMF_TO_B2C_APP_SERVICE_CONFIG[app.id]) {
                    throw new GQLError(ERRORS.APP_NOT_ALLOWED, context)
                }

                const b2cApp = await getByCondition('B2CApp', { id: app.id, deletedAt: null })
                if (!b2cApp) {
                    throw new GQLError(ERRORS.APP_NOT_FOUND, context)
                }

                const callStatus = await getCallStatus({ b2cAppId: app.id, callId })

                if (!callStatus) {
                    throw new GQLError(ERRORS.CALL_NOT_FOUND, context)
                }

                const error = await sendDTMFCode({ 
                    url: SEND_DTMF_TO_B2C_APP_SERVICE_CONFIG[app.id]?.url, 
                    accessToken: SEND_DTMF_TO_B2C_APP_SERVICE_CONFIG[app.id]?.accessToken, 
                    dtmfCode,
                })
                if (error) {
                    throw new GQLError(error, context)
                }

                return {
                    status: 'OK',
                }
            },
        },
    ],
    
})

module.exports = {
    SendDTMFToB2CAppService,
}
